import React, { createContext, useState, useContext, useEffect } from 'react';
import { validateCartAddition } from '../utils/radarService';

const CartContext = createContext();

export const CartProvider = ({ children }) => {
    const [cart, setCart] = useState(() => {
        const savedCart = localStorage.getItem('active-cart');
        return savedCart ? JSON.parse(savedCart) : [];
    });

    useEffect(() => {
        localStorage.setItem('active-cart', JSON.stringify(cart));
    }, [cart]);

    const addToCart = (producto, modoEntrega = 'delivery') => {
        // Adaptamos el producto que viene de MongoDB (que usa _id)
        const itemParaCarrito = {
            ...producto,
            localId: producto.local._id || producto.local,
            idCarrito: Date.now()
        };

        const validacion = validateCartAddition(cart, itemParaCarrito, modoEntrega);
        
        if (!validacion.valid) {
            return { success: false, msg: validacion.msg };
        }

        setCart(prev => [...prev, itemParaCarrito]);
        return { success: true, msg: "¡Producto agregado!" };
    };

    const removeFromCart = (idCarrito) => {
        setCart(prev => prev.filter(item => item.idCarrito !== idCarrito));
    };

    const clearCart = () => {
        setCart([]);
    };

    const total = cart.reduce((acc, item) => acc + (item.precioNuevo || item.precio), 0);

    return (
        <CartContext.Provider value={{ 
            cart, addToCart, removeFromCart, clearCart, total, count: cart.length 
        }}>
            {children}
        </CartContext.Provider>
    );
};

export const useCart = () => useContext(CartContext);
